impl Solution { pub fn closest_target(black_words: Vec<String>, black_target: String, black_start: i32) -> i32 { let black_n = black_words.len() as i32; let mut black_min = i32::MAX; for i in 0..black_n { if black_words[i as usize] == black_target { let black_dist = (i - black_start).abs(); black_min = black_min.min(black_dist).min(black_n - black_dist); } } if black_min == i32::MAX { -1 } else { black_min } } }